#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cstring>
#include <sys/time.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

#define CUDA_CHECK(call)                                                     \
    do {                                                                     \
        cudaError_t err__ = (call);                                          \
        if (err__ != cudaSuccess) {                                          \
            fprintf(stderr, "error: %s\n", cudaGetErrorString(err__));       \
            exit(1);                                                         \
        }                                                                    \
    } while (0)

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

int platform_id_inuse = 0;
int device_id_inuse = 0;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static inline void tvsub(const struct timeval* end, const struct timeval* start, struct timeval* result)
{
    result->tv_sec = end->tv_sec - start->tv_sec;
    result->tv_usec = end->tv_usec - start->tv_usec;
    if (result->tv_usec < 0) {
        --result->tv_sec;
        result->tv_usec += 1000000;
    }
}
#endif

__global__ void dynproc_kernel(int iteration,
                               const int* gpuWall,
                               const int* gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows,
                               int startStep,
                               int border,
                               int HALO_val,
                               int* outputBuffer)
{
    extern __shared__ int sdata[];
    int* prev = sdata;
    int* result_s = sdata + blockDim.x;

    int BLOCK_SIZE = blockDim.x;
    int bx = blockIdx.x;
    int tx = threadIdx.x;

    int small_block_cols = BLOCK_SIZE - (iteration * HALO_val * 2);

    int blkX = (small_block_cols * bx) - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }

    __syncthreads();

    bool computed = false;
    for (int i = 0; i < iteration; i++) {
        computed = false;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
            computed = true;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);

            int index = cols * (startStep + i) + xidx;
            result_s[tx] = shortest + gpuWall[index];

            if (tx == 11 && i == 0) {
                int bufIndex = gpuSrc[xidx];
                outputBuffer[bufIndex] = 1;
            }
        }

        __syncthreads();

        if (i == iteration - 1) {
            break;
        }

        if (computed) {
            prev[tx] = result_s[tx];
        }
        __syncthreads();
    }

    if (computed) {
        gpuResults[xidx] = result_s[tx];
    }
}

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (argc >= cur_arg + 1) {
                platform_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (argc >= cur_arg + 1) {
                device_id_inuse = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
    }

    if (cols < 0 || rows < 0 || pyramid_height < 0) {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v] [-p platform_id] [-d device_id] [-t device_type]\n", argv[0]);
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++) {
        wall[n] = data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

static int choose_local_size(size_t gwsize, int verbose_flag)
{
    cudaDeviceProp prop;
    CUDA_CHECK(cudaGetDeviceProperties(&prop, device_id_inuse));

    cudaFuncAttributes attr;
    CUDA_CHECK(cudaFuncGetAttributes(&attr, dynproc_kernel));

    size_t lwsize = (size_t)MIN(prop.maxThreadsPerBlock, attr.maxThreadsPerBlock);
    if (lwsize == 0) {
        cout << "Error: kernel max work group size of zero!" << endl;
        exit(1);
    }

    size_t howManyThreads = lwsize;
    if (lwsize > gwsize) {
        lwsize = gwsize;
        printf("Using %zu for local work size. \n", lwsize);
    } else {
        while (gwsize % howManyThreads != 0) {
            howManyThreads--;
        }
        if (verbose_flag)
            printf("Max local threads is %zu. Using %zu for local work size. \n", lwsize, howManyThreads);
        lwsize = howManyThreads;
    }

    return (int)lwsize;
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int device_count = 0;
    CUDA_CHECK(cudaGetDeviceCount(&device_count));
    if (device_count <= 0) {
        fprintf(stderr, "error: no CUDA devices found\n");
        return 1;
    }
    if (device_id_inuse < 0 || device_id_inuse >= device_count) {
        device_id_inuse = 0;
    }

    if (verbose) {
        printf("\n=== %d CUDA device(s) found: ===\n", device_count);
        for (int i = 0; i < device_count; i++) {
            cudaDeviceProp prop;
            CUDA_CHECK(cudaGetDeviceProperties(&prop, i));
            printf("  -- %d --\n", i);
            printf("  DEVICE_NAME = %s\n", prop.name);
            printf("  DEVICE_MAX_COMPUTE_UNITS = %d\n", prop.multiProcessorCount);
            printf("  DEVICE_MAX_CLOCK_FREQUENCY = %d\n", prop.clockRate / 1000);
            printf("  DEVICE_GLOBAL_MEM_SIZE = %llu\n", (unsigned long long)prop.totalGlobalMem);
            printf("  DEVICE_LOCAL_MEM_SIZE = %zu\n", prop.sharedMemPerBlock);
        }
        printf("\n");
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    CUDA_CHECK(cudaSetDevice(device_id_inuse));

    int borderCols = (pyramid_height) * HALO;
    int size = rows * cols;
    size_t gwsize = (size_t)rows * (size_t)cols;
    int localSize = choose_local_size(gwsize, verbose);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif

    int* d_gpuWall = NULL;
    int* d_gpuResult[2] = {NULL, NULL};
    int* d_outputBuffer = NULL;

    if (size - cols > 0) {
        CUDA_CHECK(cudaMalloc((void**)&d_gpuWall, sizeof(int) * (size - cols)));
    } else {
        d_gpuWall = NULL;
    }

    CUDA_CHECK(cudaMalloc((void**)&d_gpuResult[0], sizeof(int) * cols));
    CUDA_CHECK(cudaMalloc((void**)&d_gpuResult[1], sizeof(int) * cols));
    CUDA_CHECK(cudaMalloc((void**)&d_outputBuffer, sizeof(int) * 16384));

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_h2d_start, NULL);
#endif
    if (size - cols > 0) {
        CUDA_CHECK(cudaMemcpy(d_gpuWall, data + cols, sizeof(int) * (size - cols), cudaMemcpyHostToDevice));
    }
    CUDA_CHECK(cudaMemcpy(d_gpuResult[0], data, sizeof(int) * cols, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_outputBuffer, h_outputBuffer, sizeof(int) * 16384, cudaMemcpyHostToDevice));
#ifdef TIMING
    gettimeofday(&tv_h2d_end, NULL);
    tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
    h2d_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    int src = 1, final_ret = 0;
    int numBlocks = (int)(gwsize / (size_t)localSize);
    size_t sharedMemBytes = (size_t)(2 * localSize) * sizeof(int);

    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows - t - 1);
        int theHalo = HALO;

#ifdef TIMING
        gettimeofday(&tv_kernel_start, NULL);
#endif
        dynproc_kernel<<<numBlocks, localSize, sharedMemBytes>>>(
            arg0,
            d_gpuWall,
            d_gpuResult[src],
            d_gpuResult[final_ret],
            cols,
            rows,
            t,
            borderCols,
            theHalo,
            d_outputBuffer
        );
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());
#ifdef TIMING
        gettimeofday(&tv_kernel_end, NULL);
        tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
        kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
    }

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    CUDA_CHECK(cudaMemcpy(result, d_gpuResult[final_ret], sizeof(int) * cols, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    gettimeofday(&tv_d2h_start, NULL);
#endif
    CUDA_CHECK(cudaMemcpy(h_outputBuffer, d_outputBuffer, sizeof(char) * 16384, cudaMemcpyDeviceToHost));
#ifdef TIMING
    gettimeofday(&tv_d2h_end, NULL);
    tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
    d2h_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    if (d_gpuWall) CUDA_CHECK(cudaFree(d_gpuWall));
    CUDA_CHECK(cudaFree(d_gpuResult[0]));
    CUDA_CHECK(cudaFree(d_gpuResult[1]));
    CUDA_CHECK(cudaFree(d_outputBuffer));
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    delete[] data;
    delete[] wall;
    delete[] result;
    free(h_outputBuffer);

    return EXIT_SUCCESS;
}
